def range_summary(nums):
    runs = []
    current, count = nums[0], 1
    for n in nums[1:]:
        if n == current:
            count += 1
        else:
            if count > 1:
                runs.append((current, current + count - 1))
            current = n
            count = 1
    if count > 1:
        runs.append((current, current))
    result = ', '.join('-'.join(map(str, r)) if len(r) > 1 else str(r[0]) for r in runs)
    return result or ''
